// Assume data is a shared reference
struct Input<'a> {
    data: &'a [u8],
}

fn process(input: &Input) -> Output<'_>
where
    'a: '_,
{
    // ...some logic...
    let output = Output { data: input.data };
    output
}

struct Output<'a> {
    data: &'a [u8],
